const l2 mod = 1000000007;
using namespace std;
//modify: 1
int n,m,r[10],c[10],f[55],kq=0;
ii p[105];
bool table[15][15];
int in() {
    int x=0,y=0;

    for(int i=1; i<=n; i++) {
        int cnt=0;
        for(int j=1; j<=n; j++) {
            cnt+=table[i][j];
        }

        x=max(x,cnt);
    }

    for(int i=1; i<=n; i++) {
        int cnt=0;
        for(int j=1; j<=n; j++) {
            cnt+=table[j][i];
        }

        y=max(y,cnt);
    }

//    cout<<r[x]+c[y]<<endl;

    return r[x]+c[y];
}
void ql(int id,int sum) {
    for(int i=1; i<=n; i++) {
        for(int j=1; j<=n; j++) {
            if(table[i][j]) {
                table[i][j]=0;
                table[p[f[id]].st][p[f[id]].nd]=1;

                int point=in();

                if(id<m) ql(id+1,sum+point);
                else kq=max(kq,sum+point);

                table[i][j]=1;
                table[p[f[id]].st][p[f[id]].nd]=0;
            }
        }
    }
}
void s1() {
    ql(1,0);
    cout<<kq;
}
void s2() {
    s1();
}
