//            a[i][j]=;
            p[(i-1)*n+j]={i,j};
        }
    }

    for(int i=1,g; i<=5; i++) {
        cin>>g;
        table[p[g].st][p[g].nd]=1;
    }

    for(int i=1; i<=m; i++) {
        cin>>f[i];
    }

    if(n==3) s1();
