    cin>>n>>Q;
    for(int i=1,x,y; i<n; i++) {
        cin>>x>>y;
        ke[x].pb(y);
        ke[y].pb(x);
    }

//    s234();

    if(n<=1000&&Q<=1000) s1();
    else s234();
}

