int o[]={1,-1};
int n,a[105][105],b[105][105];
bool check(int mask1,int mask2) {
    for(int x=1; x<=n; x++) {
        for(int y=1; y<=n; y++) {
            if(a[x][y]*o[bit(x-1,mask1)^bit(y-1,mask2)]!=b[x][y]) {
                return 0;
            }
        }
    }

    return 1;
}
void s12() {
    int mn=1e9;
    for(int i=0; i<(1<<n); i++) {
        for(int j=0; j<(1<<n); j++) {
            if(cntbit(i)+cntbit(j)>mn) break;
            if(check(i,j)) {
                mn=cntbit(i)+cntbit(j);
            }
        }
    }

    if(mn==1e9) cout<<-1;
    else cout<<mn;
}
void s3() {
    int mn=1e9;
    for(int i=0; i<(1<<n); i++) {
        int cnt=cntbit(i);
        for(int x=1; x<=n; x++) {
            if(cnt>mn) break;
            bool check1=1,check2=1;
            //check1 - 0
            for(int y=1; y<=n; y++) {
                if(a[x][y]*o[bit(y-1,i)]!=b[x][y]) check1=0;
                if(a[x][y]*o[bit(y-1,i)^1]!=b[x][y]) check2=0;

                if(check1+check2==0) break;
            }

            if(!check1) {
                if(check2) cnt++;
                else cnt=1e9+2;
            }
        }

        if(cnt<mn) {
            mn=cnt;
        }
    }

    if(mn==1e9) cout<<-1;
    else cout<<mn;
}
void s4() {
    s3();
